/** Compact halfblock art for dashboard grid cards (18-26 chars wide) */
export function getCrawfishArt(level: number, state: AgentState): string[] {
  const clamped = Math.max(1, Math.min(5, level));
  return COMPACT[clamped][state];
}

/** High-res ASCII art for detail view (50-80 chars wide) */
export function getCrawfishHires(level: number, state: AgentState): string[] {
  const clamped = Math.max(1, Math.min(5, level));
  return HIRES[clamped][state];
}

// 3D renderer integration
import { ASCII3DRenderer, getCrawfishModel } from './renderer3d/index.js';
import type { RenderObject } from './renderer3d/index.js';
import { Vector3 } from './renderer3d/math.js';
import chalk from 'chalk';

const renderer3d = new ASCII3DRenderer(28, 12);

function getLevelColor(level: number): (s: string) => string {
  switch (level) { case 1: return chalk.hex('#aaa'); case 2: return chalk.hex('#00bcd4'); case 3: return chalk.hex('#4caf50'); case 4: return chalk.hex('#ffc107'); case 5: return chalk.hex('#ff1744'); default: return chalk.hex('#aaa'); }
}

export function getCrawfish3D(level: number, state: AgentState, frame: number): string[] {
  const model = getCrawfishModel(level);
  const rotSpeed = state === 'working' ? 0.05 : state === 'idle' ? 0.02 : 0;
  const rotY = frame * rotSpeed;
  const bobY = state === 'working' ? Math.sin(frame * 0.1) * 0.1 : 0;
  const obj: RenderObject = { mesh: model, position: new Vector3(0, bobY, 0), rotation: new Vector3(0.3, rotY, 0), scale: new Vector3(1, 1, 1) };
  const rendered = renderer3d.render([obj]);
  const colorFn = getLevelColor(level);
  return rendered.map(line => colorFn(line));
}
